import pytest

def test_create_team_missing_mandatory_field_returns_400(manager_auth_headers, api_client):
    payload = {
        "department": "Engineering",
        "manager_id": "<fixture:manager_id>"
        # 'name' intentionally omitted
    }

    response = api_client.post("/api/teams", json=payload, headers=manager_auth_headers)

    assert response.status_code == 400, (
        f"Expected 400 for missing 'name', got {response.status_code}: {response.text}"
    )

    body = response.json()
    error_text = str(body).lower()
    assert "name" in error_text, (
        f"Error response should reference the missing field 'name', got: {body}"
    )

